#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX 1000001
#define INF INT_MAX

int min(int a, int b) { return a < b ? a : b; }

int bfs(int **graph, int *dist, int src, int n) {
    int *visited = (int *)calloc(n, sizeof(int));
    int *queue = (int *)calloc(n, sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = src;
    visited[src] = 1;
    dist[src] = 0;
    while (front < rear) {
        int u = queue[front++];
        for (int v = 0; v < n; v++) {
            if (graph[u][v] == 1 && !visited[v]) {
                queue[rear++] = v;
                visited[v] = 1;
                dist[v] = dist[u] + 1;
            }
        }
    }
    free(visited);
    free(queue);
    return 0;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int **graph = (int **)calloc(n, sizeof(int *));
        for (int i = 0; i < n; i++) {
            graph[i] = (int *)calloc(n, sizeof(int));
        }
        for (int i = 0; i < n - 1; i++) {
            graph[i][i + 1] = graph[i + 1][i] = 1;
        }
        for (int i = 0; i < k; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--; v--;
            graph[u][v] = graph[v][u] = 1;
        }
        long long sum = 0;
        for (int i = 0; i < n; i++) {
            int *dist = (int *)calloc(n, sizeof(int));
            for (int j = 0; j < n; j++) {
                dist[j] = INF;
            }
            bfs(graph, dist, i, n);
            for (int j = i + 1; j < n; j++) {
                sum += dist[j];
            }
            free(dist);
        }
        for (int i = 0; i < n; i++) {
            free(graph[i]);
        }
        free(graph);
        printf("%lld\n", sum);
    }
    return 0;
}

