import java.util.Scanner;
import java.util.Queue;
import java.util.LinkedList;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            int k = sc.nextInt();
            int[][] graph = new int[n][n];
            for (int i = 0; i < n - 1; i++) {
                graph[i][i + 1] = graph[i + 1][i] = 1;
            }
            for (int i = 0; i < k; i++) {
                int u = sc.nextInt() - 1;
                int v = sc.nextInt() - 1;
                graph[u][v] = graph[v][u] = 1;
            }
            long sum = 0;
            for (int i = 0; i < n; i++) {
                int[] dist = new int[n];
                for (int j = 0; j < n; j++) {
                    dist[j] = Integer.MAX_VALUE;
                }
                dist[i] = 0;
                Queue<Integer> q = new LinkedList<>();
                q.add(i);
                while (!q.isEmpty()) {
                    int u = q.poll();
                    for (int v = 0; v < n; v++) {
                        if (graph[u][v] == 1 && dist[v] > dist[u] + 1) {
                            dist[v] = dist[u] + 1;
                            q.add(v);
                        }
                    }
                }
                for (int j = i + 1; j < n; j++) {
                    sum += dist[j];
                }
            }
            System.out.println(sum);
        }
    }
}

